#term-line {
  display: flex;
  align-items: center;
  font-size: 24px;
  letter-spacing: 0.02em;
}

.term-prompt {
  color: var(--accent);
  opacity: 0.9;
  margin-right: 8px;
}

#term-input { color: var(--ink); white-space: pre; }
#term-input.is-dim { color: var(--accent-warm); opacity: 0.92; }

/* Confirm step (the link-checkpoint Y/N prompt): it's a question, not a typed
   command — drop the $ prompt + cursor and let it wrap instead of overflowing. */
#term-line.is-confirm .term-prompt,
#term-line.is-confirm .term-cursor { display: none; }
#term-line.is-confirm #term-input { white-space: normal; line-height: 1.3; }

/* Call-to-action: the actionable command/keys — the brightest thing here */
#term-cta {
  display: flex;
  align-items: center;
  gap: 10px;
  margin-top: 13px;
}
#term-cta:empty { display: none; }
.cta-label {
  font-size: 13px;
  letter-spacing: 0.24em;
  font-weight: 700;
  color: var(--accent);
  opacity: 0.9;
}
.cta-cmd {
  font-family: ui-monospace, "SF Mono", Menlo, monospace;
  font-size: 16px;
  font-weight: 700;
  letter-spacing: 0.02em;
  color: #04121a;
  padding: 5px 14px;
  border-radius: 7px;
