  box-shadow: 0 0 18px rgba(111, 227, 255, 0.45);
}
.cta-key {
  display: inline-grid;
  place-items: center;
  min-width: 36px;
  height: 36px;
  padding: 0 11px;
  font-family: ui-monospace, "SF Mono", Menlo, monospace;
  font-size: 21px;
  font-weight: 700;
  border-radius: 7px;
  color: #04121a;
}
.cta-key-yes {
  background: linear-gradient(90deg, #6fe3ff, #9af0ff);
  box-shadow: 0 0 14px rgba(111, 227, 255, 0.45);
}
.cta-key-no {
  background: rgba(232, 244, 255, 0.16);
  color: var(--ink);
  border: 1px solid rgba(232, 244, 255, 0.3);
}
.cta-note {
  font-size: 21px;
  color: var(--ink);
  opacity: 0.82;
  margin-right: 8px;
}

/* Helper under the command line (replaces the old #-hint + "TYPE" label chip).
